('business:2-2-market-research:fib:a275cff7', 'business', 'business:2-2-market-research', '2.2 Market Research', 'fib', 'fib', 2, '{"question": "Qualitative data is based on the _____ of consumers. Quantitative data is related to facts and _____, and is usually easier to analyse.", "blankOptions": {"B1": ["down", "market", "marketing", "opinions"], "B2": ["numbers", "cheaper", "facts", "ten"]}}'::jsonb, '{"blanks": {"B1": "opinions", "B2": "numbers"}}'::jsonb),
